  function lca(node) {
    if (!node || node.val === a || node.val === b) return node;
    const left = lca(node.left), right = lca(node.right);
    if (left && right) return node;
    return left || right;
  }
  function dist(node, target, d) {
    if (!node) return -1;
    if (node.val === target) return d;
    const left = dist(node.left, target, d + 1);
    return left !== -1 ? left : dist(node.right, target, d + 1);
  }
  const ancestor = lca(root);
  return dist(ancestor, a, 0) + dist(ancestor, b, 0);
}
```

