## Greedy Net Settlement

Compute net balance for each person. Repeatedly find the max creditor and max debtor, settle the minimum of their absolute balances.

```js
function minimizeCashFlowAmongAGivenSetOfFriendsWhoHaveBorrowedMoneyFromEachOther(graph) {
  const n = graph.length;
  const net = new Array(n).fill(0);
  for (let i = 0; i < n; i++)
    for (let j = 0; j < n; j++) { net[i] -= graph[i][j]; net[j] += graph[i][j]; }
  const result = [];
  function settle() {
    let maxC = 0, maxD = 0;
    for (let i = 1; i < n; i++) {
      if (net[i] > net[maxC]) maxC = i;
      if (net[i] < net[maxD]) maxD = i;
    }
    if (net[maxC] === 0 && net[maxD] === 0) return;
    const amt = Math.min(-net[maxD], net[maxC]);
    net[maxC] -= amt; net[maxD] += amt;
    result.push([maxD, maxC, amt]);
    settle();
  }
  settle();
  return result;
}
```

