## Cycle Detection

Create (value, index) pairs, sort by value. Count cycles by following the index chain — each cycle of length k needs k-1 swaps.

```js
function minimumSwapsToSortAnArray(arr) {
  const n = arr.length;
  const indexed = arr.map((v, i) => [v, i]).sort((a, b) => a[0] - b[0]);
  const visited = new Array(n).fill(false);
  let swaps = 0;
  for (let i = 0; i < n; i++) {
    if (visited[i] || indexed[i][1] === i) continue;
    let cycleLen = 0, j = i;
    while (!visited[j]) { visited[j] = true; j = indexed[j][1]; cycleLen++; }
    swaps += cycleLen - 1;
  }
  return swaps;
}
```

