## BST Traversal

Traverse the BST. Track predecessor/successor based on comparison. When key is found, predecessor is rightmost in left subtree, successor is leftmost in right subtree.

```js
function predecessorAndSuccessor(root, key) {
  let pred = null, succ = null, node = root;
  while (node) {
    if (key < node.val) { succ = node.val; node = node.left; }
    else if (key > node.val) { pred = node.val; node = node.right; }
    else {
      if (node.left) { let p = node.left; while (p.right) p = p.right; pred = p.val; }
      if (node.right) { let s = node.right; while (s.left) s = s.left; succ = s.val; }
      break;
    }
  }
  return [pred, succ];
}
```

**Time:** O(h)
**Space:** O(1)

## Upper Bound Approach

Use a global index and upper bound. First element is root. Recursively build left (bound = root val) and right (bound = parent bound) subtrees.

```js
function preorderToBst(preorder) {
  let i = 0;
  function build(bound) {
    if (i >= preorder.length || preorder[i] > bound) return null;
    const node = { val: preorder[i++], left: null, right: null };
    node.left = build(node.val);
    node.right = build(bound);
    return node;
  }
  return build(Infinity);
}
```

**Time:** O(n)
**Space:** O(n)

## Prim's with Min-Heap

Start from vertex 0. Use a min-heap to pick the cheapest edge to an unvisited vertex. Add the weight to MST and mark visited.

```js
function primSAlgorithmForMinimumSpanningTreeMst(V, adj) {
  const visited = new Array(V).fill(false);
  const heap = [[0, 0]];
  let mstCost = 0, count = 0;
  while (heap.length && count < V) {
    heap.sort((a, b) => a[0] - b[0]);
    const [w, u] = heap.shift();
    if (visited[u]) continue;
    visited[u] = true; mstCost += w; count++;
    for (let v = 0; v < V; v++)
      if (!visited[v] && adj[u][v] > 0) heap.push([adj[u][v], v]);
  }
  return mstCost;
}
```

**Time:** O(V^2 log V)
**Space:** O(V^2)

## DFS with Path Tracking

DFS maintaining the current path. At each node, check all suffixes of the path for the target sum.

```js
function printAllKSumPathsInABinaryTree(root, k) {
  const result = [];
  function dfs(node, path) {
    if (!node) return;
    path.push(node.val);
    let sum = 0;
    for (let i = path.length - 1; i >= 0; i--) {
      sum += path[i];
      if (sum === k) result.push(path.slice(i));
    }
    dfs(node.left, path); dfs(node.right, path);
    path.pop();
  }
  dfs(root, []);
  return result;
}
```

