## Backtracking

DFS from (0,0) exploring D, L, R, U (sorted order). Mark visited cells to avoid cycles. Collect paths reaching (n-1,n-1).

```js
function ratInAMazeProblemI(maze) {
  const n = maze.length, result = [];
  const dirs = [['D',1,0],['L',0,-1],['R',0,1],['U',-1,0]];
  function dfs(r, c, path) {
    if (r === n-1 && c === n-1) { result.push(path); return; }
    for (const [ch, dr, dc] of dirs) {
      const nr = r+dr, nc = c+dc;
      if (nr >= 0 && nr < n && nc >= 0 && nc < n && maze[nr][nc] === 1) {
        maze[r][c] = 0;
        dfs(nr, nc, path + ch);
        maze[r][c] = 1;
      }
    }
  }
  if (maze[0][0] === 1) dfs(0, 0, '');
  return result;
}
```

**Time:** O(4^(n^2))
**Space:** O(n^2)

## Split, Reverse, Merge

Find the middle. Reverse the second half. Interleave both halves.

```js
function rearrangeAGivenLinkedListInPlace(head) {
  if (!head || !head.next) return head;
  let slow = head, fast = head;
  while (fast.next && fast.next.next) { slow = slow.next; fast = fast.next.next; }
  let second = slow.next; slow.next = null;
  let prev = null;
  while (second) { const next = second.next; second.next = prev; prev = second; second = next; }
  let first = head; second = prev;
  while (second) {
    const t1 = first.next, t2 = second.next;
    first.next = second; second.next = t1;
    first = t1; second = t2;
  }
  return head;
}
```

**Time:** O(n)
**Space:** O(1)

## Flag-based Swap

Traverse maintaining a flag for < or > comparison. Swap values when the condition is violated.

```js
function rearrangeALinkedListInZigZagFashion(head) {
  if (!head) return head;
  let curr = head, flag = true;
  while (curr.next) {
    if (flag) {
      if (curr.val > curr.next.val)
        [curr.val, curr.next.val] = [curr.next.val, curr.val];
    } else {
      if (curr.val < curr.next.val)
        [curr.val, curr.next.val] = [curr.next.val, curr.val];
    }
    curr = curr.next; flag = !flag;
  }
  return head;
}
```

**Time:** O(n)
**Space:** O(1)

## In-Order Traversal

During in-order traversal, find two violations. The first swapped node is before the first disorder; the second is after the last disorder. Swap their values.

```js
function recoverBinarySearchTree(root) {
  let first = null, second = null, prev = null;
  function inorder(node) {
    if (!node) return;
    inorder(node.left);
    if (prev && prev.val > node.val) {
      if (!first) first = prev;
      second = node;
    }
    prev = node;
    inorder(node.right);
  }
  inorder(root);
  [first.val, second.val] = [second.val, first.val];
  return root;
}
```

**Time:** O(n)
**Space:** O(h)

