## 3D DP

dp[l][r][k] = max points for boxes[l..r] with k extra same-color boxes attached to left. Either remove boxes[l] with extras for (k+1)^2, or merge with same-color boxes later.

```js
function removeBoxes(boxes) {
  const n = boxes.length;
  const dp = Array.from({length: n}, () =>
    Array.from({length: n}, () => new Array(n).fill(0)));
  function solve(l, r, k) {
    if (l > r) return 0;
    if (dp[l][r][k]) return dp[l][r][k];
    let ll = l, kk = k;
    while (ll+1 <= r && boxes[ll+1] === boxes[l]) { ll++; kk++; }
    let res = (kk+1)*(kk+1) + solve(ll+1, r, 0);
    for (let i = ll+2; i <= r; i++)
      if (boxes[i] === boxes[l])
        res = Math.max(res, solve(ll+1, i-1, 0) + solve(i, r, kk+1));
    return dp[l][r][k] = res;
  }
  return solve(0, n-1, 0);
}
```

**Time:** O(n^4)
**Space:** O(n^3)

